   public void setupAnim(T entity, float limbSwing, float limbSwingAmount, float ageInTicks, float netHeadYaw, float headPitch) {
      this.right_leg1.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.right_leg2.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.Head.yRot = netHeadYaw / 57.295776F;
      this.Head.xRot = headPitch / 57.295776F;
      this.right_leg7.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg1.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.left_leg2.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.right_leg5.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg3.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.right_leg6.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.left_leg4.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.right_leg3.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg5.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.right_leg4.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
      this.left_leg6.xRot = Mth.cos(limbSwing * 1.0F) * -1.0F * limbSwingAmount;
      this.left_leg7.xRot = Mth.cos(limbSwing * 1.0F) * 1.0F * limbSwingAmount;
   }
